'use client';

import { useEffect, useState } from 'react';
import Link from 'next/link';
import { useAuth } from '@/contexts/auth-context';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Skeleton } from '@/components/ui/skeleton';
import {
  FileTextIcon,
  ClockIcon,
  CheckCircleIcon,
  XCircleIcon,
  HourglassSimpleIcon,
  ArrowRightIcon,
  PlusIcon,
  EyeIcon,
} from '@phosphor-icons/react';
import type { Application, ApplicationStatus } from '@/lib/types';

interface DashboardStats {
  total: number;
  draft: number;
  submitted: number;
  under_review: number;
  additional_info_required: number;
  reviewed: number;
  approved: number;
  rejected: number;
}

export default function DashboardPage() {
  const { user, permissions } = useAuth();
  const [applications, setApplications] = useState<Application[]>([]);
  const [stats, setStats] = useState<DashboardStats | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    async function fetchData() {
      try {
        const response = await fetch('/api/applications');
        if (response.ok) {
          const data = await response.json();
          setApplications(data.applications || []);

          // Calculate stats
          const apps = data.applications || [];
          setStats({
            total: apps.length,
            draft: apps.filter((a: Application) => a.status === 'draft').length,
            submitted: apps.filter((a: Application) => a.status === 'submitted').length,
            under_review: apps.filter((a: Application) => a.status === 'under_review').length,
            additional_info_required: apps.filter((a: Application) => a.status === 'additional_info_required').length,
            reviewed: apps.filter((a: Application) => a.status === 'reviewed').length,
            approved: apps.filter((a: Application) => a.status === 'approved').length,
            rejected: apps.filter((a: Application) => a.status === 'rejected').length,
          });
        }
      } catch (error) {
        console.error('Failed to fetch applications:', error);
      } finally {
        setIsLoading(false);
      }
    }

    fetchData();
  }, []);

  const getStatusBadge = (status: ApplicationStatus) => {
    const config: Record<ApplicationStatus, { variant: 'default' | 'secondary' | 'destructive' | 'outline'; label: string }> = {
      draft: { variant: 'outline', label: 'Draft' },
      submitted: { variant: 'secondary', label: 'Submitted' },
      under_review: { variant: 'default', label: 'Under Review' },
      additional_info_required: { variant: 'outline', label: 'Info Required' },
      reviewed: { variant: 'secondary', label: 'Reviewed' },
      approved: { variant: 'default', label: 'Approved' },
      rejected: { variant: 'destructive', label: 'Rejected' },
    };
    const { variant, label } = config[status];
    return <Badge variant={variant}>{label}</Badge>;
  };

  const recentApplications = applications.slice(0, 5);

  return (
    <div className="space-y-6">
      <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Dashboard</h1>
          <p className="text-muted-foreground">
            Welcome back, {user?.name}
          </p>
        </div>
        {permissions?.canCreateApplication && (
          <Link href="/applications/new">
            <Button className="gap-2">
              <PlusIcon size={16} weight="bold" />
              New Application
            </Button>
          </Link>
        )}
      </div>

      {/* Stats Grid */}
      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
        {isLoading ? (
          <>
            {[...Array(4)].map((_, i) => (
              <Card key={i}>
                <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                  <Skeleton className="h-4 w-24" />
                  <Skeleton className="h-4 w-4" />
                </CardHeader>
                <CardContent>
                  <Skeleton className="h-8 w-16" />
                </CardContent>
              </Card>
            ))}
          </>
        ) : (
          <>
            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Total Applications</CardTitle>
                <FileTextIcon className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">{stats?.total || 0}</div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Pending Review</CardTitle>
                <ClockIcon className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">
                  {(stats?.submitted || 0) + (stats?.under_review || 0)}
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Awaiting Decision</CardTitle>
                <HourglassSimpleIcon className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">{stats?.reviewed || 0}</div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Completed</CardTitle>
                <CheckCircleIcon className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="flex items-center gap-4">
                  <div className="flex items-center gap-1">
                    <CheckCircleIcon className="h-4 w-4 text-green-500" />
                    <span className="text-lg font-semibold">{stats?.approved || 0}</span>
                  </div>
                  <div className="flex items-center gap-1">
                    <XCircleIcon className="h-4 w-4 text-destructive" />
                    <span className="text-lg font-semibold">{stats?.rejected || 0}</span>
                  </div>
                </div>
              </CardContent>
            </Card>
          </>
        )}
      </div>

      {/* Role-specific guidance */}
      {user?.role === 'reviewer' && (
        <Card className="border-blue-200 bg-blue-50/50 dark:border-blue-900 dark:bg-blue-950/30">
          <CardHeader>
            <CardTitle className="text-lg">Reviewer Tasks</CardTitle>
            <CardDescription>
              Applications waiting for your review
            </CardDescription>
          </CardHeader>
          <CardContent>
            <p className="text-sm text-muted-foreground mb-4">
              As a reviewer, you can examine submitted applications, request additional information,
              and provide recommendations for approval or rejection.
            </p>
            <Link href="/applications?status=submitted">
              <Button variant="outline" className="gap-2">
                View Pending Applications
                <ArrowRightIcon size={16} />
              </Button>
            </Link>
          </CardContent>
        </Card>
      )}

      {user?.role === 'approver' && (
        <Card className="border-purple-200 bg-purple-50/50 dark:border-purple-900 dark:bg-purple-950/30">
          <CardHeader>
            <CardTitle className="text-lg">Approval Tasks</CardTitle>
            <CardDescription>
              Applications awaiting final decision
            </CardDescription>
          </CardHeader>
          <CardContent>
            <p className="text-sm text-muted-foreground mb-4">
              As an approver, you make the final decision on reviewed applications.
              Note: You cannot approve applications that you have reviewed (maker-checker principle).
            </p>
            <Link href="/applications?status=reviewed">
              <Button variant="outline" className="gap-2">
                View Applications for Approval
                <ArrowRightIcon size={16} />
              </Button>
            </Link>
          </CardContent>
        </Card>
      )}

      {/* Recent Applications */}
      <Card>
        <CardHeader className="flex flex-row items-center justify-between">
          <div>
            <CardTitle>Recent Applications</CardTitle>
            <CardDescription>
              {user?.role === 'applicant' 
                ? 'Your latest license applications' 
                : 'Latest applications in the system'}
            </CardDescription>
          </div>
          <Link href="/applications">
            <Button variant="outline" size="sm" className="gap-2">
              View All
              <ArrowRightIcon size={16} />
            </Button>
          </Link>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <div className="space-y-4">
              {[...Array(3)].map((_, i) => (
                <div key={i} className="flex items-center justify-between rounded-lg border p-4">
                  <div className="space-y-2">
                    <Skeleton className="h-4 w-48" />
                    <Skeleton className="h-3 w-32" />
                  </div>
                  <Skeleton className="h-6 w-20" />
                </div>
              ))}
            </div>
          ) : recentApplications.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-8 text-center">
              <FileTextIcon className="h-12 w-12 text-muted-foreground/50 mb-4" />
              <p className="text-muted-foreground">No applications yet</p>
              {permissions?.canCreateApplication && (
                <Link href="/applications/new" className="mt-4">
                  <Button className="gap-2">
                    <PlusIcon size={16} />
                    Create Your First Application
                  </Button>
                </Link>
              )}
            </div>
          ) : (
            <div className="space-y-3">
              {recentApplications.map((app) => (
                <Link
                  key={app.id}
                  href={`/applications/${app.id}`}
                  className="flex items-center justify-between rounded-lg border p-4 transition-colors hover:bg-muted/50"
                >
                  <div className="min-w-0 flex-1">
                    <div className="flex items-center gap-2">
                      <span className="font-medium truncate">{app.bankName}</span>
                      <span className="text-xs text-muted-foreground font-mono">
                        {app.referenceNumber}
                      </span>
                    </div>
                    <p className="text-sm text-muted-foreground truncate capitalize">
                      {app.bankType} Bank
                    </p>
                  </div>
                  <div className="flex items-center gap-3">
                    {getStatusBadge(app.status)}
                    <EyeIcon className="h-4 w-4 text-muted-foreground" />
                  </div>
                </Link>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}
